import React, { useState } from 'react';
import axios from 'axios';

const CreateListing = () => {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    price: '',
    category: 'Shirts', // Default category
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Retrieve seller info from local storage
    const sellerId = localStorage.getItem('userId'); // In a real app, decode the JWT or store ID separately
    const sellerEmail = localStorage.getItem('userEmail');

    if (!sellerId) {
      alert("User session expired. Please log in again.");
      return;
    }

    try {
      await axios.post('http://localhost:5000/api/items/create', {
        ...formData,
        sellerId: sellerId,
        sellerEmail: sellerEmail
      });
      alert('Listing created successfully!');
      window.location.href = '/dashboard';
    } catch (err) {
      console.error(err);
      alert('Error creating listing');
    }
  };

  return (
    <div style={{ padding: '40px', maxWidth: '500px', margin: 'auto' }}>
      <h2>List a Vintage Item</h2>
      <form onSubmit={handleSubmit}>
        <input name="title" placeholder="Item Title" onChange={handleChange} required style={inputStyle} />
        <textarea name="description" placeholder="Description" onChange={handleChange} required style={inputStyle} />
        <input name="price" type="number" placeholder="Price ($)" onChange={handleChange} required style={inputStyle} />
        
        <select name="category" onChange={handleChange} style={inputStyle}>
          <option value="Shirts">Shirts</option>
          <option value="Jackets">Jackets</option>
          <option value="Pants">Pants</option>
          <option value="Accessories">Accessories</option>
        </select>
        
        <button type="submit" style={{ width: '100%', padding: '10px', background: '#1a1a1a', color: 'white' }}>
          Post Listing
        </button>
      </form>
    </div>
  );
};

const inputStyle = { width: '100%', padding: '10px', marginBottom: '15px', display: 'block' };

export default CreateListing;
